INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1, 190805, 62, 0.0, "カリン", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, 1000001, "2030/01/01 14:59:59", -416.5, 1, 3.414);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1, 190805, 62, 0.0, "カリン", "ミッションをクリアして、\n報酬をゲットしましょう！", 1, 1000002, "2030/01/01 14:59:59", -416.5, 2, 3.099);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1, 190805, 63, 0.0, "カリン", "受け取ることができる\n報酬があるようです\n確認してみてください", 1, 1000003, "2030/01/01 14:59:59", -416.5, 3, 2.801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1, 190805, 63, 0.0, "カリン", "報酬がもらえますよ！\nチェックしてみてください", 2, 1000004, "2030/01/01 14:59:59", -416.5, 4, 0.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1, 190805, 64, 0.0, "カリン", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 2, 1000005, "2030/01/01 14:59:59", -363.0, 5, 2.12);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 1, 190805, 64, 0.0, "カリン", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1, 1000006, "2030/01/01 14:59:59", -363.0, 6, 1.68);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 1, 190805, 64, 0.0, "カリン", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 2, 1000007, "2030/01/01 14:59:59", -363.0, 7, 2.33);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, "2025/01/31 12:00:00", 10201, 133701, 61, -6.0, "ラビリスタ", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 3, 1020101, "2030/01/01 14:59:59", -285.0, 101, 5.18);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/01/31 12:00:00", 10201, 133901, 61, -2.0, "クリスティーナ", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1, 1020102, "2030/01/01 14:59:59", -285.0, 201, 8.77);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/01/31 12:00:00", 10201, 133801, 61, 0.0, "ネネカ", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 6, 1020103, "2030/01/01 14:59:59", -285.0, 301, 15.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5, "2025/02/28 12:00:00", 10202, 134301, 61, 0.0, "ランファ", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 2, 1020201, "2030/01/01 14:59:59", -285.0, 101, 9.061);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/02/28 12:00:00", 10202, 134401, 61, 0.0, "チカ", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1, 1020202, "2030/01/01 14:59:59", -285.0, 201, 7.699);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/03/31 12:00:00", 10203, 134601, 61, 0.0, "アオイ", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1, 1020301, "2030/01/01 14:59:59", -285.0, 101, 8.595);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/03/31 12:00:00", 10203, 134501, 61, 0.0, "クローチェ", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1, 1020302, "2030/01/01 14:59:59", -285.0, 201, 7.758);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, "2025/04/30 12:00:00", 10204, 132302, 61, 0.0, "ルイズマリー", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 2, 1020401, "2030/01/01 14:59:59", -285.0, 101, 7.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/04/30 12:00:00", 10204, 132402, 61, 0.0, "イロハ", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1, 1020402, "2030/01/01 14:59:59", -285.0, 201, 7.904);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/04/30 12:00:00", 10204, 132502, 61, 0.0, "ソノ", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 4, 1020403, "2030/01/01 14:59:59", -285.0, 301, 8.487);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/05/31 12:00:00", 10205, 134901, 61, 0.0, "カノン", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1, 1020502, "2030/01/01 14:59:59", -285.0, 101, 8.763);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/05/31 12:00:00", 10205, 134801, 61, 0.0, "ツムギ", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1, 1020503, "2030/01/01 14:59:59", -285.0, 201, 6.417);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, "2025/06/30 12:00:00", 10206, 135001, 61, 0.0, "エリス", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 3, 1020601, "2030/01/01 14:59:59", -285.0, 101, 10.335);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/06/30 12:00:00", 10206, 135101, 61, 0.0, "シェフィ", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 2, 1020602, "2030/01/01 14:59:59", -285.0, 201, 6.281);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/06/30 12:00:00", 10206, 135201, 61, 0.0, "プレシア", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1, 1020603, "2030/01/01 14:59:59", -285.0, 301, 12.244);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8, "2025/07/31 12:00:00", 10207, 135301, 61, 0.0, "クリア", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 2, 1020701, "2030/01/01 14:59:59", -285.0, 101, 6.339);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9, "2025/07/31 12:00:00", 10207, 135401, 61, 0.0, "アネモネ", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 7, 1020702, "2030/01/01 14:59:59", -285.0, 201, 8.184);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/08/31 12:00:00", 10208, 129101, 61, 0.0, "アイラ", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 9, 1020801, "2030/01/01 14:59:59", -285.0, 101, 3.906);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/08/31 12:00:00", 10208, 129201, 61, 0.0, "シナツ", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1, 1020802, "2030/01/01 14:59:59", -285.0, 201, 14.465);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/08/31 12:00:00", 10208, 100101, 61, 0.0, "ヒヨリ", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 4, 1020803, "2030/01/01 14:59:59", -285.0, 301, 8.662);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2025/08/31 12:00:00", 10208, 100301, 61, 0.0, "レイ", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1, 1020804, "2030/01/01 14:59:59", -285.0, 401, 10.915);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, "2025/09/30 12:00:00", 10209, 135802, 61, 0.0, "ユキノ", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1, 1020901, "2030/01/01 14:59:59", -285.0, 101, 6.042);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/09/30 12:00:00", 10209, 135903, 61, 0.0, "サツキ", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 4, 1020902, "2030/01/01 14:59:59", -285.0, 201, 9.402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/09/30 12:00:00", 10209, 136902, 61, 0.0, "ルルィ", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 8, 1020903, "2030/01/01 14:59:59", -285.0, 301, 8.16);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/10/31 12:00:00", 10210, 137401, 61, 0.0, "カスミ", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 3, 1021001, "2030/01/01 14:59:59", -285.0, 101, 5.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2025/10/31 12:00:00", 10210, 136001, 61, 0.0, "アラクネ", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 4, 1021002, "2030/01/01 14:59:59", -285.0, 201, 8.12);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/10/31 12:00:00", 10210, 136202, 61, 0.0, "ナーナ", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 4, 1021003, "2030/01/01 14:59:59", -285.0, 301, 6.386);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, "2025/11/30 12:00:00", 10211, 136402, 61, 0.0, "ユイ", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 3, 1021101, "2030/01/01 14:59:59", -285.0, 101, 7.438);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5, "2025/11/30 12:00:00", 10211, 136302, 61, 0.0, "ミソラ", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1, 1021102, "2030/01/01 14:59:59", -285.0, 201, 8.35);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/12/31 12:00:00", 10212, 136501, 61, 0.0, "シズル", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1, 1021201, "2030/01/01 14:59:59", -285.0, 101, 5.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/12/31 12:00:00", 10212, 137902, 61, 0.0, "リノ", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1, 1021202, "2030/01/01 14:59:59", -285.0, 201, 5.25);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2025/12/31 12:00:00", 10212, 106801, 61, 0.0, "ラビリスタ", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1, 1021203, "2030/01/01 14:59:59", -285.0, 301, 7.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/01/31 12:00:00", 10213, 126501, 61, 0.0, "ライラエル", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1, 1021301, "2030/01/01 14:59:59", -285.0, 101, 8.204);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/01/31 12:00:00", 10213, 129701, 61, 0.0, "ネフィ＝ネラ", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1, 1021302, "2030/01/01 14:59:59", -285.0, 201, 7.176);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5, "2026/01/31 12:00:00", 10213, 133101, 61, 0.0, "ヴァイオレット", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1, 1021303, "2030/01/01 14:59:59", -285.0, 301, 8.602);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2026/02/06 12:00:00", 10213, 138101, 61, 0.0, "ライラエル", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1, 1021304, "2030/01/01 14:59:59", -285.0, 102, 10.14);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, "2026/02/06 12:00:00", 10213, 138201, 61, 0.0, "ネフィ＝ネラ", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1, 1021305, "2030/01/01 14:59:59", -285.0, 202, 10.152);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2026/02/06 12:00:00", 10213, 138001, 61, 0.0, "ヴァイオレット", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 4, 1021306, "2030/01/01 14:59:59", -285.0, 302, 9.688);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, "2026/02/12 12:00:00", 10213, 138301, 61, 0.0, "ペコリーヌ", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 2, 1021307, "2030/01/01 14:59:59", -285.0, 401, 5.928);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, "2026/02/28 12:00:00", 10214, 138702, 61, 0.0, "ワカナ", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 4, 1021401, "2030/01/01 14:59:59", -285.0, 101, 9.19);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, "2026/02/28 12:00:00", 10214, 138802, 61, 0.0, "シオリ", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1, 1021402, "2030/01/01 14:59:59", -285.0, 201, 8.724);
